func TestOpenStoreForReadUsesReadOnlyHandle(t *testing.T) {
	t.Setenv("HOME", t.TempDir())

	dbPath := defaultDBPath("airflow-admin-pp-cli")
	db, err := store.OpenWithContext(context.Background(), dbPath)
	if err != nil {
		t.Fatalf("open writable store: %v", err)
	}
	if err := db.Close(); err != nil {
		t.Fatalf("close writable store: %v", err)
	}

	ro, err := openStoreForRead(context.Background(), nil, "airflow-admin-pp-cli")
	if err != nil {
		t.Fatalf("open read store: %v", err)
	}
	if ro == nil {
		t.Fatalf("open read store returned nil for existing database")
	}
	defer ro.Close()

	if _, err := ro.DB().Exec(`CREATE TABLE read_path_write_probe (id TEXT)`); err == nil {
		t.Fatalf("read store accepted a write")
	}
}

func TestOpenStoreForReadHonorsRootDBPath(t *testing.T) {
	t.Setenv("HOME", t.TempDir())

	customPath := t.TempDir() + "/custom.db"
	db, err := store.OpenWithContext(context.Background(), customPath)
	if err != nil {
		t.Fatalf("open writable custom store: %v", err)
	}
	if err := db.Close(); err != nil {
		t.Fatalf("close writable custom store: %v", err)
	}

	ro, err := openStoreForRead(context.Background(), &rootFlags{dbPath: customPath}, "airflow-admin-pp-cli")
	if err != nil {
		t.Fatalf("open read custom store: %v", err)
	}
	if ro == nil {
		t.Fatalf("open read custom store returned nil")
	}
	defer ro.Close()

	if ro.Path() != customPath {
		t.Fatalf("read store path = %q, want %q", ro.Path(), customPath)
	}
}

func TestRootDBFlagRoutesLocalSearchToCustomStore(t *testing.T) {
	t.Setenv("HOME", t.TempDir())

	customPath := filepath.Join(t.TempDir(), "custom.db")
	db, err := store.OpenWithContext(context.Background(), customPath)
	if err != nil {
		t.Fatalf("open writable custom store: %v", err)
	}
	if err := db.Upsert("dags", "custom_validation_dag", json.RawMessage(`{"dag_id":"custom_validation_dag","id":"custom_validation_dag"}`)); err != nil {
		t.Fatalf("seed custom store: %v", err)
	}
	if err := db.Close(); err != nil {
		t.Fatalf("close custom store: %v", err)
	}

	flags := &rootFlags{}
	cmd := newRootCmd(flags)
	var out, stderr bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetErr(&stderr)
	cmd.SetArgs([]string{"search", "custom_validation_dag", "--data-source", "local", "--db", customPath, "--json"})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("search custom store: %v\nstderr: %s", err, stderr.String())
	}
	if !strings.Contains(out.String(), "custom_validation_dag") {
		t.Fatalf("search output did not include custom-store row\nstdout: %s\nstderr: %s", out.String(), stderr.String())
	}
}
